// API Key authentication check - timing-safe comparison
const headers = $input.first().json.headers || {};

// Case-insensitive header lookup (defense against platform normalization changes)
const headerKeys = Object.keys(headers);
const apiKeyHeader = headerKeys.find(k => k.toLowerCase() === 'x-api-key');
const providedKey = apiKeyHeader ? headers[apiKeyHeader] : '';
const expectedKey = $env.LOCALAI_API_KEY;

// Timing-safe comparison - prevents timing attacks on API key
function timingSafeEqual(a, b) {
  if (typeof a !== 'string' || typeof b !== 'string') return false;
  const MAX_LEN = 256;

  // Include bounds check in result (constant-time, no branch)
  let result = (a.length > MAX_LEN || b.length > MAX_LEN) ? 1 : 0;
  // Constant-time comparison: always iterate MAX_LEN, use 0 for out-of-bounds
  for (let i = 0; i < MAX_LEN; i++) {
    const charA = i < a.length ? a.charCodeAt(i) : 0;
    const charB = i < b.length ? b.charCodeAt(i) : 0;
    result |= charA ^ charB;
  }
  // Include length check in constant-time result (CRITICAL: prevents length oracle attacks)
  result |= (a.length === b.length) ? 0 : 1;
  return result === 0;
}

// CRITICAL: Always validate API key if provided, regardless of expectedKey
// This prevents fail-open vulnerability when env var is unset
// Authentication logic:
// - If server has expectedKey configured: client MUST provide matching key
// - If server has NO expectedKey configured: reject any request that provides a key (unauthorized)
// - If neither configured: allow (no auth required)
if ((expectedKey || providedKey) && !timingSafeEqual(providedKey || '', expectedKey || '')) {
  return [{ json: { valid: false, error: 'Authentication failed' } }];
}

// Parse and validate input
const input = $input.first().json || {};
const messages = input.messages;

// Validate messages is an array with at least one message
if (!Array.isArray(messages) || messages.length === 0) {
  return [{ json: { valid: false, error: 'messages must be a non-empty array' } }];
}

// Validate each message has role and content
for (let i = 0; i < messages.length; i++) {
  const msg = messages[i];
  if (!msg.role || !msg.content) {
    return [{ json: { valid: false, error: 'Each message must have role and content' } }];
  }
  if (typeof msg.content !== 'string') {
    return [{ json: { valid: false, error: 'Message content must be a string' } }];
  }
}

// Validate model name if provided (basic alphanumeric + hyphen/underscore)
const model = input.model || 'gpt-4';
if (typeof model !== 'string' || model.length === 0) {
  return [{ json: { valid: false, error: 'model must be a non-empty string' } }];
}

// Validate max_tokens if provided
const maxTokens = input.max_tokens;
if (maxTokens !== undefined) {
  if (typeof maxTokens !== 'number' || maxTokens < 1 || maxTokens > 32000) {
    return [{ json: { valid: false, error: 'max_tokens must be a number between 1 and 32000' } }];
  }
}

// Validate temperature if provided
const temperature = input.temperature;
if (temperature !== undefined) {
  if (typeof temperature !== 'number' || temperature < 0 || temperature > 2) {
    return [{ json: { valid: false, error: 'temperature must be a number between 0 and 2' } }];
  }
}

return [{
  json: {
    valid: true,
    messages: messages,
    model: model,
    temperature: temperature,
    max_tokens: maxTokens,
    stream: input.stream || false
  }
}];

